    10→/// Implementation of [AuthRepository] that coordinates between local and remote data sources
    11→class AuthRepositoryImpl implements AuthRepository {
    12→  final AuthRemoteDataSource remoteDataSource;
    13→  final AuthLocalDataSource localDataSource;
    14→  final SecurityManager securityManager;
    15→
    16→  /// Creates a new [AuthRepositoryImpl] with the given data sources
    17→  const AuthRepositoryImpl({
    18→    required this.remoteDataSource,
    19→    required this.localDataSource,
    20→    required this.securityManager,
    21→  });
    22→
    23→  @override
    24→  Future<User> signInWithEmailAndPassword(String email, String password) async {
    25→    try {
    26→      // Check for rate limiting
    27→      await securityManager.checkLoginAttempts();
    28→
    29→      final (user, token) = await remoteDataSource.signIn(email, password);
    30→
    31→      // Check if this is a new device
    32→      if (!await securityManager.isKnownDevice()) {
    33→        // In a real app, you might want to require additional verification here
    34→        await securityManager.registerDevice();
    35→      }
    36→
    37→      // With Cognito, we don't need to store refresh tokens as the SDK handles that
    38→      await localDataSource.saveAuthData(token, token);
    39→      await localDataSource.cacheUser(user);
    40→      await securityManager.resetLoginAttempts();
    41→      return user;
    42→    } on AuthException {
    43→      // Record the failed attempt but preserve the original error
    44→      await securityManager.recordFailedLoginAttempt();
    45→      rethrow;
    46→    } catch (e) {
    47→      await securityManager.recordFailedLoginAttempt();
    48→      throw AuthException('Failed to sign in: ${e.toString()}');
    49→    }
    50→  }

