    23→
    24→  /// Creates a new [ApiClient] with the given configuration
    25→  ApiClient({
    26→    required String baseUrl,
    27→    required AuthInterceptor authInterceptor,
    28→    required ErrorInterceptor errorInterceptor,
    29→    required NetworkMonitor networkMonitor,
    30→  })  : _dio = Dio(BaseOptions(baseUrl: baseUrl)),
    31→        _networkMonitor = networkMonitor {
    32→    _dio.interceptors.addAll([
    33→      authInterceptor,
    34→      errorInterceptor,
    35→    ]);
    36→  }
    37→
    38→  /// Sets whether the client is in offline mode
    39→  @override
    40→  void setOfflineMode(bool offline) {
    41→    _isOffline = offline;
    42→  }
    43→
    44→  /// Sets the authorization token for all future requests
    45→  @override
    46→  void setAuthToken(String token) {
