    56→  @override
    57→  Future<Map<String, dynamic>> get(String endpoint) async {
    58→    if (_isOffline) {
    59→      throw Exception('No internet connection');
    60→    }
    61→
    62→    try {
    63→      final stopwatch = Stopwatch()..start();
    64→      _networkMonitor.trackRequest(endpoint);
    65→
    66→      final response = await _dio.get<Map<String, dynamic>>(endpoint);
    67→      stopwatch.stop();
    68→
    69→      _networkMonitor.trackRequestAndResponse(
    70→        path: endpoint,
    71→        duration: stopwatch.elapsed,
    72→        statusCode: response.statusCode ?? 0,
    73→        responseSize: _calculateResponseSize(response),
    74→      );
    75→
    76→      return response.data ?? {};
    77→    } catch (error) {
    78→      _handleRequestError(endpoint, error);
    79→      rethrow;
    80→    }
