   168→  /// Make a PATCH request to the specified [path]
   169→  Future<Map<String, dynamic>> patch(String endpoint,
   170→      {Map<String, dynamic>? data}) async {
   171→    if (_isOffline) {
   172→      throw Exception('No internet connection');
   173→    }
   174→
   175→    try {
   176→      final stopwatch = Stopwatch()..start();
   177→      _networkMonitor.trackRequest(endpoint);
   178→
   179→      final response =
   180→          await _dio.patch<Map<String, dynamic>>(endpoint, data: data);
   181→      stopwatch.stop();
   182→
   183→      _networkMonitor.trackRequestAndResponse(
   184→        path: endpoint,
   185→        duration: stopwatch.elapsed,
   186→        statusCode: response.statusCode ?? 0,
   187→        responseSize: _calculateResponseSize(response),
